#include <iostream>
#include <string>
#include <algorithm>
#include <cctype>

bool isPalindrome(const std::string& s) {
    if (s.empty()) {
        return true;
    }

    int left = 0;
    int right = s.length() - 1;

    while (left < right) {
        while (left < right && !std::isalnum(s[left])) {
            left++;
        }
        while (left < right && !std::isalnum(s[right])) {
            right--;
        }

        if (left >= right) {
            break;
        }

        if (std::tolower(s[left]) != std::tolower(s[right])) {
            return false;
        }

        left++;
        right--;
    }

    return true;
}

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        if (isPalindrome(line)) {
            std::cout << "Yes, \"" << line << "\" is a palindrome." << std::endl;
        } else {
            std::cout << "No, \"" << line << "\" is not a palindrome." << std::endl;
        }
    }
    return 0;
}
